# Grafana HTTP API: restrict prompt-audit datasource to prompt-audit-reviewers only
# (Run by the observability team, not by individual engineers)
curl -X POST https://grafana.example.com/api/datasources/uid/<DS_UID>/permissions \
  -H "Content-Type: application/json" \
  -H "Authorization: Bearer $GRAFANA_ADMIN_TOKEN" \
  -d '{
    "items": [
      {
        "teamId": 0,
        "userId": 0,
        "builtInRole": "Admin",
        "permission": 2
      },
      {
        "teamId": <PROMPT_AUDIT_REVIEWER_TEAM_ID>,
        "userId": 0,
        "permission": 1
      }
