  }'

# scripts/quarterly_access_review.py
# Generates a report of all users with production log access
import requests

GRAFANA_URL = "https://grafana.example.com"
ADMIN_TOKEN = "..."

def get_users_with_role(role_name: str) -> list[dict]:
    users = requests.get(
        f"{GRAFANA_URL}/api/org/users",
        headers={"Authorization": f"Bearer {ADMIN_TOKEN}"},
    ).json()
    return [u for u in users if u.get("role") == role_name or role_name in u.get("roles", [])]

def generate_access_report() -> str:
    lines = ["# Quarterly Log Access Review", ""]
    for role in ["observability-leads", "genai-oncall", "prompt-audit-reviewer"]:
        users = get_users_with_role(role)
        lines.append(f"## {role} ({len(users)} users)")
        for u in users:
            lines.append(f"- {u['email']} (last login: {u.get('lastSeenAt', 'unknown')})")
        lines.append("")

    # Highlight users who haven't logged in for 90+ days
    lines.append("## Stale Access — No Login in 90+ Days")
    from datetime import datetime, timedelta, timezone
    cutoff = datetime.now(timezone.utc) - timedelta(days=90)
    for role in ["observability-leads", "genai-oncall"]:
        for u in get_users_with_role(role):
            last_seen = u.get("lastSeenAtAge", "")
            if "year" in last_seen or (
                u.get("lastSeenAt") and
                datetime.fromisoformat(u["lastSeenAt"].replace("Z", "+00:00")) < cutoff
            ):
                lines.append(f"- REVIEW: {u['email']} ({role}) — {last_seen}")
    return "\n".join(lines)

if __name__ == "__main__":
    report = generate_access_report()
    print(report)
    # Post to Slack / send via email to team leads for review
